#include "envoy/extensions/filters/http/custom_header_injection/v3/custom_header_injection.pb.validate.h"
#include "envoy/registry/registry.h"

#include "source/common/protobuf/utility.h"
#include "source/extensions/filters/http/custom_header_injection/filter.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjectionFilter {

Http::FilterFactoryCb CustomHeaderInjectionConfig::createFilterFactoryFromProtoTyped(
    const envoy::extensions::filters::http::custom_header_injection::v3::Config& proto_config,
    const std::string&, Server::Configuration::FactoryContext&) {
  ConfigSharedPtr filter_config(std::make_shared<Config>(proto_config));

  return [filter_config](Http::FilterChainFactoryCallbacks& callbacks) -> void {
    callbacks.addStreamFilter(
        Http::StreamFilterSharedPtr{new CustomHeaderInjectionFilter(filter_config)});
  };
}

absl::StatusOr<Router::RouteSpecificFilterConfigConstSharedPtr>
CustomHeaderInjectionConfig::createRouteSpecificFilterConfigTyped(
    const envoy::extensions::filters::http::custom_header_injection::v3::Config& config,
    Server::Configuration::ServerFactoryContext&, ProtobufMessage::ValidationVisitor&) {
  return std::make_shared<const Config>(config);
}

/**
 * Static registration for the custom header injection filter.
 */
REGISTER_FACTORY(CustomHeaderInjectionConfig, Server::Configuration::NamedHttpFilterConfigFactory);

} // namespace CustomHeaderInjectionFilter
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include <memory>

#include "envoy/extensions/filters/http/custom_header_injection/v3/custom_header_injection.pb.h"

#include "source/common/http/header_map_impl.h"
#include "source/common/protobuf/protobuf.h"
#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "test/mocks/http/mocks.h"
#include "test/mocks/stream_info/mocks.h"
#include "test/test_common/utility.h"

#include "gmock/gmock.h"
#include "gtest/gtest.h"

using testing::NiceMock;

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjectionFilter {
namespace {

class CustomHeaderInjectionTest : public testing::Test {
public:
  const std::string request_config_yaml = R"EOF(
headers:
  - header_name: x-custom-header
    header_value: custom-value
    apply_to_request: true
    apply_to_response: false
  - header_name: x-both-header
    header_value: both-value
    apply_to_request: true
    apply_to_response: true
)EOF";

  const std::string response_config_yaml = R"EOF(
headers:
  - header_name: x-response-header
    header_value: response-value
    apply_to_request: false
    apply_to_response: true
)EOF";

  void initializeFilter(const std::string& yaml) {
    envoy::extensions::filters::http::custom_header_injection::v3::Config config;
    TestUtility::loadFromYaml(yaml, config);
    config_ = std::make_shared<Config>(config);
    filter_ = std::make_shared<CustomHeaderInjectionFilter>(config_);
    filter_->setDecoderFilterCallbacks(decoder_callbacks_);
    filter_->setEncoderFilterCallbacks(encoder_callbacks_);
  }

  ConfigSharedPtr config_;
  std::shared_ptr<CustomHeaderInjectionFilter> filter_;
  NiceMock<Http::MockStreamDecoderFilterCallbacks> decoder_callbacks_;
  NiceMock<Http::MockStreamEncoderFilterCallbacks> encoder_callbacks_;
};

/**
 * Test basic request header injection.
 */
TEST_F(CustomHeaderInjectionTest, BasicRequestHeaderInjection) {
  initializeFilter(request_config_yaml);
  Http::TestRequestHeaderMapImpl incoming_headers{{"x-original", "original-value"}};

  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(incoming_headers, false));

  // Check that the request header was injected
  EXPECT_EQ(incoming_headers.get(Http::LowerCaseString("x-custom-header")), "custom-value");
  EXPECT_EQ(incoming_headers.get(Http::LowerCaseString("x-both-header")), "both-value");

  filter_->onDestroy();
}

/**
 * Test basic response header injection.
 */
TEST_F(CustomHeaderInjectionTest, BasicResponseHeaderInjection) {
  initializeFilter(response_config_yaml);
  Http::TestResponseHeaderMapImpl incoming_headers{{"x-original-response", "original-value"}};

  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->encodeHeaders(incoming_headers, false));

  // Check that the response header was injected
  EXPECT_EQ(incoming_headers.get(Http::LowerCaseString("x-response-header")), "response-value");

  filter_->onDestroy();
}

/**
 * Test headers applied to both request and response.
 */
TEST_F(CustomHeaderInjectionTest, HeaderInjectionBothPaths) {
  initializeFilter(request_config_yaml);

  // Test request
  Http::TestRequestHeaderMapImpl request_headers{{"x-original", "original-value"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(request_headers, false));
  EXPECT_EQ(request_headers.get(Http::LowerCaseString("x-both-header")), "both-value");

  // Test response
  Http::TestResponseHeaderMapImpl response_headers{{"x-original-response", "original-value"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->encodeHeaders(response_headers, false));
  EXPECT_EQ(response_headers.get(Http::LowerCaseString("x-both-header")), "both-value");

  filter_->onDestroy();
}

/**
 * Test empty configuration.
 */
TEST_F(CustomHeaderInjectionTest, EmptyConfiguration) {
  initializeFilter("{}");

  Http::TestRequestHeaderMapImpl request_headers{{"x-original", "original-value"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(request_headers, false));

  Http::TestResponseHeaderMapImpl response_headers{{"x-original-response", "original-value"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->encodeHeaders(response_headers, false));

  filter_->onDestroy();
}

/**
 * Test that filter returns Continue for data and trailers.
 */
TEST_F(CustomHeaderInjectionTest, DataAndTrailersPassthrough) {
  initializeFilter(request_config_yaml);

  Buffer::OwnedImpl data("test data");
  EXPECT_EQ(Http::FilterDataStatus::Continue, filter_->decodeData(data, false));

  Http::TestRequestTrailerMapImpl trailers;
  EXPECT_EQ(Http::FilterTrailersStatus::Continue, filter_->decodeTrailers(trailers));

  filter_->onDestroy();
}

} // namespace
} // namespace CustomHeaderInjectionFilter
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

syntax = "proto3";

package envoy.extensions.filters.http.custom_header_injection.v3;

import "udpa/annotations/status.proto";
import "udpa/annotations/versioning.proto";
import "validate/validate.proto";

option java_package = "io.envoyproxy.envoy.extensions.filters.http.custom_header_injection.v3";
option java_outer_classname = "CustomHeaderInjectionProto";
option java_multiple_files = true;
option go_package = "github.com/envoyproxy/go-control-plane/envoy/extensions/filters/http/custom_header_injection/v3;custom_header_injectionv3";
option (udpa.annotations.file_status).package_version_status = ACTIVE;

// [#protodoc-title: Custom Header Injection Filter]
//
// The configuration for injecting custom headers into requests and/or responses.
//
// Custom Header Injection :ref:`configuration overview <config_http_filters_custom_header_injection>`.
// [#extension: envoy.filters.http.custom_header_injection]

message Config {
  option (udpa.annotations.versioning).previous_message_type =
      "envoy.extensions.filters.http.custom_header_injection.v3.Config";

  // HeaderRule defines a header to inject.
  message HeaderRule {
    // The name of the header to inject.
    string header_name = 1 [(validate.rules).string = {
      well_known_regex: HTTP_HEADER_NAME
      strict: false
    }];

    // The value of the header to inject.
    string header_value = 2;

    // Whether to apply this header to request headers.
    bool apply_to_request = 3;

    // Whether to apply this header to response headers.
    bool apply_to_response = 4;
  }

  // The list of header rules to apply.
  repeated HeaderRule headers = 1;
}

