156: bool HeaderToMetadataFilter::addMetadata(StructMap& struct_map, const std::string& meta_namespace,
157:                                          const std::string& key, std::string value, ValueType type,
158:                                          ValueEncode encode) const {
159:   ProtobufWkt::Value val;
160: 
161:   ASSERT(!value.empty());
162: 
163:   if (value.size() >= MAX_HEADER_VALUE_LEN) {
164:     // Too long, go away.
165:     ENVOY_LOG(debug, "metadata value is too long");
166:     return false;
167:   }
168: 
169:   if (encode == envoy::extensions::filters::http::header_to_metadata::v3::Config::BASE64) {
170:     value = Base64::decodeWithoutPadding(value);
171:     if (value.empty()) {
172:       ENVOY_LOG(debug, "Base64 decode failed");
173:       return false;
174:     }
175:   }
176: 
177:   // Sane enough, add the key/value.
178:   switch (type) {
179:     PANIC_ON_PROTO_ENUM_SENTINEL_VALUES;
180:   case envoy::extensions::filters::http::header_to_metadata::v3::Config::STRING:
181:     val.set_string_value(std::move(value));
182:     break;
183:   case envoy::extensions::filters::http::header_to_metadata::v3::Config::NUMBER: {
184:     double dval;
185:     if (absl::SimpleAtod(StringUtil::trim(value), &dval)) {
186:       val.set_number_value(dval);
187:     } else {
188:       ENVOY_LOG(debug, "value to number conversion failed");
189:       return false;
190:     }
191:     break;
192:   }
193:   case envoy::extensions::filters::http::header_to_metadata::v3::Config::PROTOBUF_VALUE: {
194:     if (!val.ParseFromString(value)) {
195:       ENVOY_LOG(debug, "parse from decoded string failed");
196:       return false;
197:     }
198:     break;
199:   }
200:   }
201: 
202:   auto& keyval = struct_map[meta_namespace];
203:   (*keyval.mutable_fields())[key] = std::move(val);
204: 
205:   return true;
206: }
