260:     return effective_config_;
261:   }
262: 
263:   effective_config_ = Http::Utility::resolveMostSpecificPerFilterConfig<Config>(decoder_callbacks_);
264:   if (effective_config_) {
265:     return effective_config_;
266:   }
267: 
268:   effective_config_ = config_.get();
269:   return effective_config_;
