16: Config::Config(const envoy::extensions::filters::http::set_metadata::v3::Config& proto_config,
17:                Stats::Scope& scope, const std::string& stats_prefix)
18:     : stats_(generateStats(stats_prefix, scope)) {
19:   if (proto_config.has_value() && !proto_config.metadata_namespace().empty()) {
20:     UntypedMetadataEntry deprecated_api_val{true, proto_config.metadata_namespace(),
21:                                             proto_config.value()};
22:     untyped_.emplace_back(deprecated_api_val);
23:   }
24: 
25:   for (const auto& metadata : proto_config.metadata()) {
26:     if (metadata.has_value()) {
27:       UntypedMetadataEntry untyped_entry{metadata.allow_overwrite(), metadata.metadata_namespace(),
28:                                          metadata.value()};
29:       untyped_.emplace_back(untyped_entry);
30:     } else if (metadata.has_typed_value()) {
31:       TypedMetadataEntry typed_entry{metadata.allow_overwrite(), metadata.metadata_namespace(),
32:                                      metadata.typed_value()};
33:       typed_.emplace_back(typed_entry);
34:     } else {
35:       ENVOY_LOG(warn, "set_metadata filter configuration contains metadata entries without value "
36:                       "or typed_value");
37:     }
38:   }
