50: Http::FilterHeadersStatus SetMetadataFilter::decodeHeaders(Http::RequestHeaderMap&, bool) {
51: 
52:   // Add configured untyped metadata.
53:   if (!config_->untyped().empty()) {
54:     auto& mut_untyped_metadata =
55:         *decoder_callbacks_->streamInfo().dynamicMetadata().mutable_filter_metadata();
56: 
57:     for (const auto& entry : config_->untyped()) {
58:       if (!mut_untyped_metadata.contains(entry.metadata_namespace)) {
59:         // Insert the new entry.
60:         mut_untyped_metadata[entry.metadata_namespace] = entry.value;
61:       } else if (entry.allow_overwrite) {
62:         // Get the existing metadata at this key for merging.
63:         ProtobufWkt::Struct& orig_fields = mut_untyped_metadata[entry.metadata_namespace];
64:         const auto& to_merge = entry.value;
65: 
66:         // Merge the new metadata into the existing metadata.
67:         StructUtil::update(orig_fields, to_merge);
68:       } else {
69:         // The entry exists, and we are not allowed to overwrite -- emit a stat.
70:         config_->stats().overwrite_denied_.inc();
71:       }
72:     }
73:   }
74: 
75:   // Add configured typed metadata.
76:   if (!config_->typed().empty()) {
77:     auto& mut_typed_metadata =
78:         *decoder_callbacks_->streamInfo().dynamicMetadata().mutable_typed_filter_metadata();
79: 
80:     for (const auto& entry : config_->typed()) {
81:       if (!mut_typed_metadata.contains(entry.metadata_namespace)) {
82:         // Insert the new entry.
83:         mut_typed_metadata[entry.metadata_namespace] = entry.value;
84:       } else if (entry.allow_overwrite) {
85:         // Overwrite the existing typed metadata at this key.
86:         mut_typed_metadata[entry.metadata_namespace] = entry.value;
87:       } else {
88:         // The entry exists, and we are not allowed to overwrite -- emit a stat.
89:         config_->stats().overwrite_denied_.inc();
90:       }
91:     }
92:   }
93: 
94:   return Http::FilterHeadersStatus::Continue;
95: }
