    config_ = std::make_shared<Config>(config);
    filter_ = std::make_shared<CustomHeaderInjectionFilter>(config_);
    filter_->setDecoderFilterCallbacks(decoder_callbacks_);
    filter_->setEncoderFilterCallbacks(encoder_callbacks_);
  }

  ConfigSharedPtr config_;
  std::shared_ptr<CustomHeaderInjectionFilter> filter_;
  NiceMock<Http::MockStreamDecoderFilterCallbacks> decoder_callbacks_;
  NiceMock<Http::MockStreamEncoderFilterCallbacks> encoder_callbacks_;
};

/**
 * Test basic request header injection.
 */
TEST_F(CustomHeaderInjectionTest, BasicRequestHeaderInjection) {
  initializeFilter(request_config_yaml);
  Http::TestRequestHeaderMapImpl incoming_headers{{"x-original", "original-value"}};

  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(incoming_headers, false));

  // Check that the request header was injected
  EXPECT_EQ(incoming_headers.get(Http::LowerCaseString("x-custom-header")), "custom-value");
  EXPECT_EQ(incoming_headers.get(Http::LowerCaseString("x-both-header")), "both-value");

  filter_->onDestroy();
}

/**
 * Test basic response header injection.
 */
TEST_F(CustomHeaderInjectionTest, BasicResponseHeaderInjection) {
  initializeFilter(response_config_yaml);
  Http::TestResponseHeaderMapImpl incoming_headers{{"x-original-response", "original-value"}};

  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->encodeHeaders(incoming_headers, false));

  // Check that the response header was injected
  EXPECT_EQ(incoming_headers.get(Http::LowerCaseString("x-response-header")), "response-value");

  filter_->onDestroy();
}

/**
 * Test headers applied to both request and response.
 */
TEST_F(CustomHeaderInjectionTest, HeaderInjectionBothPaths) {
  initializeFilter(request_config_yaml);

  // Test request
  Http::TestRequestHeaderMapImpl request_headers{{"x-original", "original-value"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(request_headers, false));
  EXPECT_EQ(request_headers.get(Http::LowerCaseString("x-both-header")), "both-value");

  // Test response
  Http::TestResponseHeaderMapImpl response_headers{{"x-original-response", "original-value"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->encodeHeaders(response_headers, false));
  EXPECT_EQ(response_headers.get(Http::LowerCaseString("x-both-header")), "both-value");

  filter_->onDestroy();
}

/**
 * Test empty configuration.
 */
TEST_F(CustomHeaderInjectionTest, EmptyConfiguration) {
  initializeFilter("{}");

  Http::TestRequestHeaderMapImpl request_headers{{"x-original", "original-value"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(request_headers, false));

  Http::TestResponseHeaderMapImpl response_headers{{"x-original-response", "original-value"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->encodeHeaders(response_headers, false));

  filter_->onDestroy();
}

/**
 * Test that filter returns Continue for data and trailers.
 */
TEST_F(CustomHeaderInjectionTest, DataAndTrailersPassthrough) {
  initializeFilter(request_config_yaml);

  Buffer::OwnedImpl data("test data");
  EXPECT_EQ(Http::FilterDataStatus::Continue, filter_->decodeData(data, false));

  Http::TestRequestTrailerMapImpl trailers;
  EXPECT_EQ(Http::FilterTrailersStatus::Continue, filter_->decodeTrailers(trailers));

  filter_->onDestroy();
}

